changeSet.sql:
CREATE TABLE goods_receipts ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID NOT NULL, number VARCHAR(30) NOT NULL, party_id UUID NOT NULL, purchase_invoice_id UUID NOT NULL, warehouse_id UUID, status VARCHAR(20) NOT NULL DEFAULT 'PENDING', type VARCHAR(20) NOT NULL DEFAULT 'INBOUND', scheduled_date DATE, received_at TIMESTAMPTZ, received_by UUID, notes VARCHAR(1000), created_at TIMESTAMPTZ NOT NULL DEFAULT now(), created_by UUID, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_by UUID, version BIGINT NOT NULL DEFAULT 0, CONSTRAINT uk_goods_receipts_tenant_number UNIQUE (tenant_id, number) );
CREATE INDEX idx_goods_receipts_party ON goods_receipts(party_id); CREATE INDEX idx_goods_receipts_invoice ON goods_receipts(purchase_invoice_id); CREATE INDEX idx_goods_receipts_status ON goods_receipts(status);
CREATE TABLE goods_receipt_lines ( id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), tenant_id UUID NOT NULL, goods_receipt_id UUID NOT NULL, product_id UUID NOT NULL, lot_id UUID, uom_id UUID NOT NULL, quantity_ordered NUMERIC(19,6) NOT NULL, quantity_received NUMERIC(19,6) NOT NULL DEFAULT 0, unit_cost NUMERIC(19,4) NOT NULL DEFAULT 0, snapshot_name VARCHAR(250), snapshot_sku VARCHAR(64), status VARCHAR(20) NOT NULL DEFAULT 'PENDING', created_at TIMESTAMPTZ NOT NULL DEFAULT now(), created_by UUID, updated_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_by UUID, version BIGINT NOT NULL DEFAULT 0 );
CREATE INDEX idx_goods_receipt_lines_receipt ON goods_receipt_lines(goods_receipt_id);

DO $$
DECLARE
    t text;
    tables text[] := ARRAY['goods_receipts', 'goods_receipt_lines'];
BEGIN
    FOREACH t IN ARRAY tables LOOP
        EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY', t);
        EXECUTE format('ALTER TABLE %I FORCE ROW LEVEL SECURITY', t);

        EXECUTE format('DROP POLICY IF EXISTS tenant_isolation_select ON %I', t);
        EXECUTE format(
            'CREATE POLICY tenant_isolation_select ON %I
                FOR SELECT
                USING (tenant_id = app_current_tenant() OR app_current_tenant() IS NULL)',
            t);

        EXECUTE format('DROP POLICY IF EXISTS tenant_isolation_modify ON %I', t);
        EXECUTE format(
            'CREATE POLICY tenant_isolation_modify ON %I
                FOR ALL
                USING (tenant_id = app_current_tenant() OR app_current_tenant() IS NULL)
                WITH CHECK (tenant_id = app_current_tenant() OR app_current_tenant() IS NULL)',
            t);
    END LOOP;
END
$$;

DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'hisaberp_app') THEN
        GRANT ALL ON TABLE goods_receipts, goods_receipt_lines TO hisaberp_app;
    END IF;
END $$;
